public class DestinationAllowlist
{
    // Allowlisted domain suffixes. In production, load from configuration.
    private readonly HashSet<string> _allowedDomains = new(StringComparer.OrdinalIgnoreCase)
    {
        "api.github.com",
        "hooks.slack.com",
        "api.stripe.com",
        "api.twilio.com",
        "webhook.site",
        "httpbin.org",
        "postman-echo.com"
    };

    private readonly HashSet<string> _allowedDomainSuffixes = new(StringComparer.OrdinalIgnoreCase)
    {
        ".webhook.site",
        ".hooks.slack.com"
    };

    public bool IsAllowed(Uri uri)
    {
        var host = uri.Host.ToLowerInvariant();

        // Block IP-based URLs entirely - must use domain names
        if (IPAddress.TryParse(host, out _))
        {
            return false;
        }

        if (_allowedDomains.Contains(host))
        {
            return true;
        }

        foreach (var suffix in _allowedDomainSuffixes)
        {
            if (host.EndsWith(suffix, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }
        }

        return false;
    }
}

public class IpValidator
{
